/**
 * The proof of life: 1 ≥ 1.
 *
 * The single theorem every other theorem reduces to.
 * Zero arguments because the fact is unconditional.
 *
 * Lean: theorem proof_of_life : 1 ≥ 1 := Nat.le_refl 1
 */
export function proofOfLife(): boolean {
  return 1 >= 1;
}

/**
 * Life: w(R, v) ≥ 1 for all R, v.
 *
 * At any state -- maximum rejection, zero experience, anything --
 * weight is at least 1. The sliver guarantees existence.
 *
 * Lean: theorem life (R v : Nat) : w R v ≥ 1
 */
export function life(rounds: number, rejections: number): boolean {
  return godFormula(rounds, rejections) >= 1;
}

/**
 * The formula without the sliver: w₀ = R - min(v, R).
 *
 * Without the +1, maximum rejection produces zero. Annihilation.
 * The difference between this and godFormula is exactly 1.
 *
 * Lean: def w_no_sliver (R v : Nat) : Nat := R - min v R
 */
export function withoutSliver(rounds: number, rejections: number): number {
  return rounds - Math.min(rejections, rounds);
}

/**
 * Without the sliver, death is possible: w₀(R, R) = 0.
 *
 * Lean: theorem without_sliver_death (R : Nat) : w_no_sliver R R = 0
 */
export function withoutSliverDeath(rounds: number): boolean {
  return withoutSliver(rounds, rounds) === 0;
}

/**
 * The difference between life and death is exactly one.
 *
 * w(R, v) - w₀(R, v) = 1. Always. The sliver.
 *
 * Lean: theorem difference_is_one (R v : Nat) : w R v - w_no_sliver R v = 1
 */
export function differenceIsOne(rounds: number, rejections: number): boolean {
  return (
    godFormula(rounds, rejections) - withoutSliver(rounds, rejections) === 1
  );
}

// ═══════════════════════════════════════════════════════════════════════════
