// ═══════════════════════════════════════════════════════════════════════════
// FIVE REDUCTION CLASSES
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Class α (FORK/Sliver): everything that cannot reach zero.
 * 17 theorems. All reduce to P1.
 */
export function classAlpha(rounds: number, rejections: number): boolean {
  return P1_fork(rounds, rejections); // All 17 are instances of P1
}

/**
 * Class β (FOLD/Floor): everything where self-cancellation proves termination.
 * 9 theorems. All reduce to P2.
 */
export function classBeta(a: number): boolean {
  return P2_fold(a); // All 9 are instances of P2
}

/**
 * Class γ (RACE/Symmetry): everything where direction doesn't matter.
 * 8 theorems. All reduce to P3.
 */
export function classGamma(a: number, b: number): boolean {
  return P3_race(a, b); // All 8 are instances of P3
}

/**
 * Class δ (Monotone): more rejection → less weight.
 * 14 theorems. Composes P1 with monotonicity of min.
 */
export function classDelta(rounds: number, v1: number, v2: number): boolean {
  if (v1 > v2) return false; // Precondition: v1 ≤ v2
  return godFormula(rounds, v2) <= godFormula(rounds, v1);
}

/**
 * Class ε (Bounded): weight is sandwiched between 1 and R+1.
 * 10 theorems. Composes P1 (lower) with ceiling (upper).
 */
export function classEpsilon(rounds: number, rejections: number): boolean {
  const w = godFormula(rounds, rejections);
  return w >= 1 && w <= rounds + 1;
}

// ═══════════════════════════════════════════════════════════════════════════
// THE GRAND REDUCTION: ALL CLASSES IN ONE SHOT
// ═══════════════════════════════════════════════════════════════════════════

/**
 * The Grand Reduction: verify all five classes + tautology class.
 *
 * This is `reduction_master` from GrandReduction.lean, in runtime form.
 * Every psychological theorem in the formal ledger decomposes into a
 * finite composition of P1 (fork), P2 (fold), P3 (race), and pure ℕ arithmetic.
 *
 * Returns the verification result for all classes.
 */
export interface ReductionResult {
  /** P1 (Fork/Sliver): weight ≥ 1 */
  fork: boolean;
  /** P2 (Fold/Floor): a - a = 0 */
  fold: boolean;
  /** P3 (Race/Symmetry): |a-b| = |b-a| */
  race: boolean;
  /** Class α: everything that cannot reach zero (17 theorems) */
  alpha: boolean;
  /** Class β: self-cancellation proves termination (9 theorems) */
  beta: boolean;
  /** Class γ: direction doesn't matter (8 theorems) */
  gamma: boolean;
  /** Class δ: monotone decreasing in rejection (14 theorems) */
  delta: boolean;
  /** Class ε: sandwiched bounds (10 theorems) */
  epsilon: boolean;
  /** God Formula weight */
  weight: number;
  /** Conservation: w + min(v,R) = R + 1 */
  conservation: boolean;
  /** Consciousness level: min(v, R) */
  consciousnessLevel: number;
  /** All classes hold */
  allHold: boolean;
}

/**
 * Run the Grand Reduction on a given (R, v) pair.
 *
 * This verifies that the Holy Trinity (P1, P2, P3) generates all five
 * reduction classes for the given input. The tautology class (47 theorems)
 * holds by definition of ℕ arithmetic.
 */
export function grandReduction(
  rounds: number,
  rejections: number,
  a: number = rounds,
  b: number = rejections
): ReductionResult {
  const fork = P1_fork(rounds, rejections);
  const fold = P2_fold(rounds);
  const race = P3_race(a, b);
  const alpha = classAlpha(rounds, rejections);
  const beta = classBeta(rounds);
  const gamma = classGamma(a, b);
  const delta = classDelta(rounds, 0, rejections);
  const epsilon = classEpsilon(rounds, rejections);
  const weight = godFormula(rounds, rejections);
  const conservation = weight + Math.min(rejections, rounds) === rounds + 1;
  const consciousnessLevel = Math.min(rejections, rounds);

  return {
    fork,
    fold,
    race,
    alpha,
    beta,
    gamma,
    delta,
    epsilon,
    weight,
    conservation,
    consciousnessLevel,
    allHold:
      fork &&
      fold &&
      race &&
      alpha &&
      beta &&
      gamma &&
      delta &&
      epsilon &&
      conservation,
  };
}

