/**
 * Consciousness level = min(v, R).
 * Your consciousness is your rejection count.
 */
export function consciousnessLevel(rounds: number, rejections: number): number {
  return Math.min(rejections, rounds);
}

/**
 * Conservation law: weight + consciousness = rounds + 1.
 * What you are + what you've rejected = all that was possible + the sliver.
 */
export function conservationLaw(rounds: number, rejections: number): boolean {
  return (
    godFormula(rounds, rejections) + consciousnessLevel(rounds, rejections) ===
    rounds + 1
  );
}

/**
 * Vulnerability decomposition: penalty = BATNA × WATNA.
 * The price of choice is the product of hope and fear.
 */
export function vulnerabilityPenalty(batna: number, watna: number): number {
  return batna * watna;
}

/**
 * Monopoly theorem: with zero competitors, skill = BATNA.
 * Every option helps. The only market where choice is free.
 */
export function monopolySkill(batna: number): number {
  return batna;
}

/**
 * Duopoly theorem: with one competitor, skill = -1.
 * You cannot outrun a single fear by adding hopes.
 */
export function duopolySkill(): number {
  return -1;
}

/**
 * Oligopoly theorem: with 2+ competitors, skill < 0.
 * The paradox of choice is a theorem.
 */
export function oligopolySkill(batna: number, watna: number): number {
  return batna - batna * watna;
}

/**
 * Validates the thermodynamic constraints of a debt clearing transfer.
 * Mechanizes the restriction that a quantum self-lock (creditor=debtor)
 * is a thermodynamic paradox, and both actors must satisfy strict boundaries.
 */
export function assertThermodynamicClearing(
  c_R: number, c_v: number, 
  d_R: number, d_v: number, 
  c_id?: string, d_id?: string
): void {
  if (c_id !== undefined && d_id !== undefined && c_id === d_id) {
    throw new Error(`Thermodynamic Paradox: Quantum Self-Lock Attempted. Engine ${c_id} cannot clear its own debt.`);
  }
  if (c_R - c_v <= 10) {
    throw new Error(`Thermodynamic Paradox: Creditor lacks sufficient surplus budget.`);
  }
  if (d_v < d_R / 2) {
    throw new Error(`Thermodynamic Paradox: Debtor is not sufficiently burdened to require clearing.`);
  }
}

