/** The golden ratio inverse: the universal attractor. */
export const PHI_INV = (1 + Math.sqrt(5)) / 2 - 1; // 0.6180339887...

/**
 * Breathe toward the attractor.
 * Each breath moves one step toward PHI_INV.
 * The fixed point: breathe(PHI_INV) = PHI_INV.
 */
export function breatheToward(
  value: number,
  target: number = PHI_INV,
  rate: number = 0.01
): number {
  return value + (target - value) * rate;
}

